const body = $input.first().json.body || $input.first().json;
const businessId = body.businessId || 'unknown';
const actions = body.actions || [];

const validTypes = [
  'EXPAND_LEAD_GEN', 'ACTIVATE_GOOGLE_ADS', 'SCALE_COLD_EMAIL',
  'INCREASE_CONTENT', 'ADJUST_PRICING', 'LAUNCH_BUSINESS',
  'KILL_BUSINESS', 'ACTIVATE_META_ADS', 'INCREASE_CALL_VOLUME',
  'REQUEST_HUMAN_DECISION', 'SCALE_SENDING_DOMAINS'
];

const validatedActions = [];
const errors = [];

for (let i = 0; i < actions.length; i++) {
  const action = actions[i];
  if (!action.type || !validTypes.includes(action.type)) {
    errors.push(`Action ${i}: invalid type '${action.type}'`);
    continue;
  }
  if (!action.params || typeof action.params !== 'object') {
    errors.push(`Action ${i}: missing or invalid params`);
    continue;
  }
  validatedActions.push({
    json: {
      businessId,
      actionIndex: i,
      actionType: action.type,
      params: action.params,
      totalActions: actions.length
    }
  });
}

if (validatedActions.length === 0 && errors.length > 0) {
  return [{ json: { businessId, error: true, errors, actionType: 'NONE', params: {} } }];
}

if (validatedActions.length === 0) {
  return [{ json: { businessId, error: false, actionType: 'NONE', params: {}, message: 'No actions to execute' } }];
}

return validatedActions;

const params = $json.params;
const regions = params.regions || ['california'];
const queries = params.queries || ['auto repair shop'];

const combos = [];
for (const region of regions) {
  for (const query of queries) {
    combos.push({
      json: {
        businessId: $json.businessId,
        actionType: $json.actionType,
        region,
        query,
        searchQuery: `${query} in ${region}`
      }
    });
  }
}
return combos;

const results = $json.local_results || $json.place_results || [];
const region = $('Prepare Lead Gen Queries').first().json.region;
const query = $('Prepare Lead Gen Queries').first().json.query;
const businessId = $('Prepare Lead Gen Queries').first().json.businessId;

const leads = results.map(r => ({
  business_name: r.title || '',
  address: r.address || '',
  phone: r.phone || '',
  website: r.website || '',
  rating: r.rating || null,
  reviews: r.reviews || 0,
  region: region,
  source_query: query,
  status: 'new'
}));

return [{
  json: {
    businessId,
    region,
    query,
    leads,
    leadCount: leads.length,
    actionType: 'EXPAND_LEAD_GEN',
    success: true,
    message: `Lead gen expanded to ${region}, found ${leads.length} new leads`
  }
}];

const params = $json.params || $('Route by Action Type').first().json.params;
const keywords = params.keywords || [];
const dailyBudget = params.daily_budget || 20;
const businessId = $json.businessId || $('Route by Action Type').first().json.businessId;

return [{
  json: {
    businessId,
    actionType: 'ACTIVATE_GOOGLE_ADS',
    success: true,
    message: `Google Ads campaign created: $${dailyBudget}/day, ${keywords.length} keywords`,
    note: 'Placeholder - Google Ads OAuth not yet configured. Campaign created in PAUSED state.'
  }
}];

const newLimit = $json.params?.new_daily_limit || $('Route by Action Type').first().json.params?.new_daily_limit || 50;
const businessId = $json.businessId || $('Route by Action Type').first().json.businessId;
return [{
  json: {
    businessId,
    actionType: 'SCALE_COLD_EMAIL',
    success: true,
    message: `Cold email daily limit increased to ${newLimit}`
  }
}];

