const params = $json.params || $('Route by Action Type').first().json.params || {};
const businessId = $json.businessId || $('Route by Action Type').first().json.businessId;
return [{
  json: {
    businessId,
    actionType: 'REQUEST_HUMAN_DECISION',
    success: true,
    message: `Human decision requested: ${params.question || 'unknown question'}`,
    requiresResponse: true
  }
}];

// SCALE_SENDING_DOMAINS - Buy additional sending domains via Cloudflare
// params: { businessId, count: 2 }
const params = $json.params || {};
const businessId = $json.businessId || params.businessId || 'unknown';
const count = params.count || 2;
const accountId = $env.CLOUDFLARE_ACCOUNT_ID;
const apiToken = $env.CLOUDFLARE_API_TOKEN;
const smartleadApiKey = $env.SMARTLEAD_API_KEY;

const purchasedDomains = [];
const errors = [];

// Generate candidate domain names
const suffixes = ['hq.com', '.io', 'app.com', '.co', 'tool.com', 'suite.com', 'pro.com', 'hub.com'];
const candidates = [];
for (const suffix of suffixes) {
  if (suffix.startsWith('.')) {
    candidates.push(businessId + suffix);
  } else {
    candidates.push(businessId + suffix);
  }
  if (candidates.length >= count * 3) break; // Try 3x candidates for each desired domain
}

for (const domain of candidates) {
  if (purchasedDomains.length >= count) break;

  try {
    // Check availability
    const checkRes = await fetch(
      `https://api.cloudflare.com/client/v4/accounts/${accountId}/registrar/domains/${domain}`,
      {
        method: 'GET',
        headers: { 'Authorization': `Bearer ${apiToken}`, 'Content-Type': 'application/json' }
      }
    );
    const checkData = await checkRes.json();

    if (checkData.success && checkData.result && checkData.result.available) {
      // Register domain
      const regRes = await fetch(
        `https://api.cloudflare.com/client/v4/accounts/${accountId}/registrar/domains`,
        {
          method: 'POST',
          headers: { 'Authorization': `Bearer ${apiToken}`, 'Content-Type': 'application/json' },
          body: JSON.stringify({ name: domain })
        }
      );
      const regData = await regRes.json();

      if (regData.success) {
        // Get zone ID for DNS
        const zoneRes = await fetch(
          `https://api.cloudflare.com/client/v4/zones?name=${domain}`,
          {
            method: 'GET',
            headers: { 'Authorization': `Bearer ${apiToken}`, 'Content-Type': 'application/json' }
          }
        );
        const zoneData = await zoneRes.json();
        const zoneId = (zoneData.success && zoneData.result && zoneData.result.length > 0) ? zoneData.result[0].id : null;

        // Set up DNS records
        if (zoneId) {
          const dnsRecords = [
            { type: 'TXT', name: domain, content: 'v=spf1 include:_spf.google.com include:sendgrid.net include:smartlead.ai ~all', ttl: 3600 },
            { type: 'TXT', name: `_dmarc.${domain}`, content: 'v=DMARC1; p=none; rua=mailto:dmarc@' + domain, ttl: 3600 },
            { type: 'MX', name: domain, content: 'mx1.improvmx.com', priority: 10, ttl: 3600 },
            { type: 'MX', name: domain, content: 'mx2.improvmx.com', priority: 20, ttl: 3600 }
          ];
          for (const record of dnsRecords) {
            try {
              await fetch(`https://api.cloudflare.com/client/v4/zones/${zoneId}/dns_records`, {
                method: 'POST',
                headers: { 'Authorization': `Bearer ${apiToken}`, 'Content-Type': 'application/json' },
                body: JSON.stringify(record)
              });
            } catch (e) { /* DNS errors non-blocking */ }
          }
        }

        // Add to Smartlead
        if (smartleadApiKey) {
          try {
            await fetch(`https://server.smartlead.ai/api/v1/email-accounts/add?api_key=${smartleadApiKey}`, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                email: `outreach@${domain}`,
                from_name: businessId,
                warmup_enabled: true,
                total_warmup_per_day: 20,
                daily_limit: 30,
                track_settings: { open_tracking: true, link_tracking: true }
              })
            });
          } catch (e) {
            errors.push(`Smartlead add for ${domain}: ${e.message}`);
          }
        }

        purchasedDomains.push(domain);
      }
    }
  } catch (e) {
    errors.push(`${domain}: ${e.message}`);
  }
}

return [{
  json: {
    businessId,
    actionType: 'SCALE_SENDING_DOMAINS',
    success: purchasedDomains.length > 0,
    purchasedDomains,
    errors: errors.length > 0 ? errors : null,
    message: purchasedDomains.length > 0
      ? `Purchased ${purchasedDomains.length} new sending domain(s): ${purchasedDomains.join(', ')}. SMTP email setup may need manual configuration.`
      : `Failed to purchase sending domains. Errors: ${errors.join('; ') || 'All candidates unavailable'}`
  }
}];

const prevData = $('Scale Sending Domains').first().json;
const existingResult = $input.first().json;

// Merge existing domains with newly purchased ones
let existingDomains = [];
if (Array.isArray(existingResult)) {
  existingDomains = existingResult[0]?.sending_domains || [];
} else if (existingResult?.sending_domains) {
  existingDomains = existingResult.sending_domains;
}
if (!Array.isArray(existingDomains)) existingDomains = [];

const allDomains = [...new Set([...existingDomains, ...prevData.purchasedDomains])];

return [{
  json: {
    ...prevData,
    allDomains
  }
}];

// Collect all action results from all branches
const allItems = $input.all();
const results = allItems.map(item => ({
  actionType: item.json.actionType || 'UNKNOWN',
  success: item.json.success !== false,
  message: item.json.message || 'No message'
}));

const businessId = allItems[0]?.json?.businessId || 'unknown';
const today = new Date().toISOString().split('T')[0];

const logContent = `# CEO Action Execution Log - ${today}\n\n` +
  `**Business:** ${businessId}\n` +
  `**Executed at:** ${new Date().toISOString()}\n` +
  `**Total actions:** ${results.length}\n\n` +
  `## Actions Executed\n\n` +
  results.map((r, i) => `### ${i + 1}. ${r.actionType}\n- **Status:** ${r.success ? 'SUCCESS' : 'FAILED'}\n- **Details:** ${r.message}\n`).join('\n') +
  `\n---\n*Generated by CEO Action Executor*\n`;

const summary = results.map(r => `${r.success ? 'OK' : 'FAIL'} ${r.actionType}: ${r.message}`).join('\n');

return [{
  json: {
    businessId,
    today,
    logContent,
    summary,
    totalActions: results.length,
    successCount: results.filter(r => r.success).length,
    results
  }
}];
